  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    using namespace sqlgen::literals;

    // 1. Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    // 2. Create User and Post tables
    std::vector<User> empty_users;
    std::vector<Post> empty_posts;

    auto write_result = sqlgen::write(conn, empty_users);
    if (!write_result) {
        throw std::runtime_error("Failed to create User table");
    }

    write_result = sqlgen::write(conn, empty_posts);
    if (!write_result) {
        throw std::runtime_error("Failed to create Post table");
    }

    // 3. Build and execute the query
    auto query = sqlgen::read<std::vector<ActiveUser>>
                 | sqlgen::inner_join<Post>("user_id"_c == "user_id"_c)
                 | sqlgen::where("created_at"_c >= "2025-12-01" && "created_at"_c <= "2025-12-31")
                 | sqlgen::distinct;

    // 4. Return the result
    auto result = query(conn);
    if (!result) {
        throw std::runtime_error("Query failed");
    }

    return result.value();
}

}  // namespace query_active_users_posts
