std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        // Handle connection error - return empty vector or throw exception
        return {};
    }
    auto conn = conn_result.value();

    // Build the base query
    auto query = sqlgen::read<std::vector<Book>>;

    // Dynamically add WHERE conditions based on provided filters
    auto condition = rfl::Nothing{};

    if (filters.title_keyword) {
        condition = "title"_c.like("%" + *filters.title_keyword + "%");
    }

    if (filters.min_year) {
        if (std::holds_alternative<rfl::Nothing>(condition)) {
            condition = "year"_c >= *filters.min_year;
        } else {
            condition = condition && ("year"_c >= *filters.min_year);
        }
    }

    if (filters.genre) {
        if (std::holds_alternative<rfl::Nothing>(condition)) {
            condition = "genre"_c == *filters.genre;
        } else {
            condition = condition && ("genre"_c == *filters.genre);
        }
