    std::string category;
    double price;
  };

  bool manage_indexes() {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");

    if (!conn_result) {
      return false;
    }

    auto conn = conn_result.value();

    // Create table with IF NOT EXISTS
    auto create_table_result = (sqlgen::create_table<Product> | sqlgen::if_not_exists)(conn);
    if (!create_table_result) {
      return false;
    }

    // Create standard index on category with IF NOT EXISTS
    auto index1_result = (sqlgen::create_index<"idx_product_category", Product>("category"_c) | sqlgen::if_not_exists)(conn);
    if (!index1_result) {
      return false;
    }

    // Create unique index on sku with IF NOT EXISTS  
