    auto index3_result = (sqlgen::create_index<"idx_product_name_price", Product>("name"_c, "price"_c) | sqlgen::if_not_exists)(conn);
    if (!index3_result) {
      return false;
    }

    return true;
  }

}  // namespace schema_manage_indexes
