```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  auto conn = conn_result.value();

  // Begin transaction
  auto begin_result = conn | sqlgen::begin_transaction;
  if (!begin_result) {
    return false;
  }

  // Read from_account balance
  auto read_result = (sqlgen::read<std::vector<Account>> | 
                     where("account_id"_c == from_account_id))(conn);

  if (!read_result) {
    conn | sqlgen::rollback;
    return false;
  }

  const auto& from_account = read_result.value()[0];

  // Check sufficient funds
  if (from_account.balance < amount) {
    conn | sqlgen::rollback;
    return false;
  }

  // Update from_account (deduct amount with balance check)
  auto update_from_result = (sqlgen::update<Account>(
      set("balance"_c = "balance"_c - amount)) | 
      where("account_id"_c == from_account_id && "balance"_c >= amount))(conn);

  if (!update_from_result) {
    conn | sqlgen::rollback;
    return false;
  }

  // Update to_account (add amount)
  auto update_to_result = (sqlgen::update<Account>(
      set("balance"_c = "balance"_c + amount)) | 
      where("account_id"_c == to_account_id))(conn);

  if (!update_to_result) {
    conn | sqlgen::rollback;
    return false;
  }

  // Commit transaction
  auto commit_result = conn | sqlgen::commit;
  return commit_result;
}

}  // namespace transaction_transfer_funds
```

