Customer read_single_record_by_id(int id) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return Customer{};
  }
  auto conn = conn_res.value();

  const auto query =
      sqlgen::read<std::vector<Customer>> | where("customer_id"_c == id);

  auto res = query(conn);
  if (!res || res->empty()) {
    return Customer{};
  }
  return res->front();
}

