std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // 2. Read Sales data from database
  auto sales_result = sqlgen::read<std::vector<Sales>>(conn);
  if (!sales_result) {
    throw std::runtime_error("Failed to read sales data");
  }
  auto sales_data = sales_result.value();

  // 3. Create a map to store weekday totals
  std::vector<WeekdayStats> weekday_totals;

  // 4. Iterate through each sale and aggregate by weekday
  for (const auto& sale : sales_data) {
    // Extract weekday from sale_time using date_part function
    auto weekday = sqlgen::internal::to_weekday(sale.sale_time);

    // Find existing entry or create new one
    bool found = false;
    for (auto& stat : weekday_totals) {
      if (stat.weekday == weekday) {
        stat.total_quantity += sale.quantity;
        found = true;
        break;
      }
    }

    if (!found) {
      weekday_totals.push_back({weekday, sale.quantity});
    }
  }

  // 5. Sort the results by weekday
  std::sort(weekday_totals.begin(), weekday_totals.end(),
              [](const WeekdayStats& a, const WeekdayStats& b) {
                return a.weekday < b.weekday;
              });

  return weekday_totals;
}

